            av = a_pkgs.get(pkg_id, {}).get('resolvedVersion', 'N/A')
            status = 'CHANGED' if bv != av else 'OK'
            print(f'{proj:10s} {pkg_id:40s} {bv:10s} -> {av:10s}  {status}')
"

